<?php require 'config.php'; require_user(); $msg=''; if($_SERVER['REQUEST_METHOD']==='POST'){ verify_csrf(); $plan=$_POST['plan']??'starter'; $ref=trim($_POST['payment_reference']??''); $pl=plan_details($plan); $st=$pdo->prepare('INSERT INTO orders(user_id,plan,payment_reference) VALUES(?,?,?)');$st->execute([$_SESSION['user_id'],$plan,$ref]); $orderId=$pdo->lastInsertId(); $invoiceNo='KC-'.date('Ymd').'-'.str_pad((string)$orderId,5,'0',STR_PAD_LEFT); $pdo->prepare('INSERT INTO invoices(user_id,order_id,invoice_number,description,amount,currency,status,due_at) VALUES(?,?,?,?,?,?,?,DATE_ADD(CURDATE(), INTERVAL 7 DAY))')->execute([$_SESSION['user_id'],$orderId,$invoiceNo,$pl['name'].' hosting order',0,'NGN','unpaid']); log_activity($pdo,'order_created','Customer submitted order',null,$_SESSION['user_id']); redirect('/dashboard.php'); } $plans=active_plans(); ?>
<!doctype html><html><head><title>Order Hosting</title><link rel="stylesheet" href="/style.css"></head><body><div class="top"><div class="brand">Order Hosting</div><div class="nav"><a href="/dashboard.php">Dashboard</a></div></div><div class="card form"><h1>Select Plan</h1><form method="post"><?=csrf_field()?><label>Plan</label><select name="plan"><?php foreach($plans as $p): $pl=plan_details($p['slug']); ?><option value="<?=h($p['slug'])?>"><?=h($pl['name'])?>: <?=h($pl['sites'])?> site(s), <?=h(fmt_bytes($pl['storage_mb']*1024*1024))?> storage, <?=h(fmt_bytes($pl['db_mb']*1024*1024))?> DB, <?=h($pl['price'])?></option><?php endforeach;?></select><label>Payment Reference / Note</label><textarea name="payment_reference" placeholder="Enter bank transfer reference or payment note"></textarea><button class="btn">Submit Order</button></form></div></body></html>
